findings.recommendation:
Add a server-side allowlist check immediately after parsing oc_version:

VALID_OC_VERSIONS = {'4.14', '4.15', '4.16', '4.17', '4.18', '4.19', '4.20'}
if oc_version not in VALID_OC_VERSIONS:
    return response(400, {'error': f'Invalid oc_version: must be one of {sorted(VALID_OC_VERSIONS)}'})

Set cloud_watch_encryption_enabled = true and add kms_key_id to the ssm_sessions log group resource:

resource "aws_cloudwatch_log_group" "ssm_sessions" {
  name              = "/ecs/${var.project}-${var.stage}/ssm-sessions"
  retention_in_days = var.retention_days
  kms_key_id        = aws_kms_key.exec_session.arn
}

Use KMS encryption with a dedicated CMK:

apply_server_side_encryption_by_default {
  sse_algorithm     = "aws:kms"
  kms_master_key_id = aws_kms_key.audit_bucket.arn
}

Add an aws_efs_file_system_policy that enforces IAM authentication and requires access via access points:

resource "aws_efs_file_system_policy" "sre_home" {
  file_system_id = aws_efs_file_system.sre_home.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Effect    = "Deny"
      Principal = { AWS = "*" }
      Action    = ["elasticfilesystem:ClientMount", "elasticfilesystem:ClientWrite"]
      Resource  = aws_efs_file_system.sre_home.arn
      Condition = {
        Bool = { "elasticfilesystem:AccessedViaMountTarget" = "false" }
      }
    }]
  })
}

Add a bucket policy requiring TLS:

resource "aws_s3_bucket_policy" "audit" {
  bucket = aws_s3_bucket.audit.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Sid       = "DenyNonTLS"
      Effect    = "Deny"
      Principal = "*"
      Action    = "s3:*"
      Resource  = [aws_s3_bucket.audit.arn, "${aws_s3_bucket.audit.arn}/*"]
      Condition = { Bool = { "aws:SecureTransport" = "false" } }
    }]
  })
}
